patch:
--- a/decoder.v
+++ b/decoder.v
@@ -1,15 +1,15 @@
 module decoder_3to8(
   input [2:0] code,
   input enable,
   output reg [7:0] decoded
 );

-  always @(code)
+  always @(*)
   begin
     decoded = 8'b0;
     if (enable)
       decoded[code] = 1'b1;
   end

 endmodule

before_code:
module decoder_3to8(
  input [2:0] code,
  input enable,
  output reg [7:0] decoded
);

  always @(code)
  begin
    decoded = 8'b0;
    if (enable)
      decoded[code] = 1'b1;
  end

endmodule

after_code:
module decoder_3to8(
  input [2:0] code,
  input enable,
  output reg [7:0] decoded
);

  always @(*)
  begin
    decoded = 8'b0;
    if (enable)
      decoded[code] = 1'b1;
  end

endmodule
